import { useState, useEffect, useRef } from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import ReactPlayer from 'react-player';
import { ArrowLeft, Play, Pause, Volume2, VolumeX, Maximize, Minimize, Settings } from 'lucide-react';
import Navbar from '../components/layout/Navbar';
import { movieService } from '../services/api';

const WatchPage = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [movie, setMovie] = useState(null);
  const [playing, setPlaying] = useState(false);
  const [muted, setMuted] = useState(false);
  const [fullscreen, setFullscreen] = useState(false);
  const [volume, setVolume] = useState(0.8);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const playerRef = useRef(null);
  const containerRef = useRef(null);

  useEffect(() => {
    const fetchMovie = async () => {
      try {
        setLoading(true);
        const data = await movieService.getById(id);
        setMovie(data);
      } catch (err) {
        setError('Movie not found');
      } finally {
        setLoading(false);
      }
    };

    fetchMovie();
  }, [id]);

  useEffect(() => {
    const handleKeyDown = (e) => {
      switch (e.key) {
        case ' ':
        case 'k':
          setPlaying(p => !p);
          break;
        case 'm':
          setMuted(m => !m);
          break;
        case 'f':
          toggleFullscreen();
          break;
        case 'ArrowLeft':
          if (playerRef.current) {
            playerRef.current.seekTo(playerRef.current.getCurrentTime() - 10, 'seconds');
          }
          break;
        case 'ArrowRight':
          if (playerRef.current) {
            playerRef.current.seekTo(playerRef.current.getCurrentTime() + 10, 'seconds');
          }
          break;
        default:
          break;
      }
    };

    document.addEventListener('keydown', handleKeyDown);
    return () => document.removeEventListener('keydown', handleKeyDown);
  }, []);

  const toggleFullscreen = () => {
    if (!containerRef.current) return;

    if (!fullscreen) {
      containerRef.current.requestFullscreen?.();
    } else {
      document.exitFullscreen?.();
    }
    setFullscreen(!fullscreen);
  };

  const handlePlayPause = () => {
    setPlaying(!playing);
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-black">
        <div className="flex items-center justify-center h-screen">
          <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-netflix-red"></div>
        </div>
      </div>
    );
  }

  if (error || !movie) {
    return (
      <div className="min-h-screen bg-netflix-bg">
        <Navbar />
        <div className="flex flex-col items-center justify-center h-screen">
          <h1 className="text-2xl text-white mb-4">{error || 'Movie not found'}</h1>
          <Link to="/" className="btn-primary">Go Home</Link>
        </div>
      </div>
    );
  }

  return (
    <div ref={containerRef} className="min-h-screen bg-black">
      <div className="fixed top-0 left-0 right-0 z-50 p-4">
        <button 
          onClick={() => navigate(-1)} 
          className="flex items-center gap-2 text-white/80 hover:text-white transition-colors bg-black/50 px-3 py-2 rounded"
        >
          <ArrowLeft size={20} />
          Back
        </button>
      </div>

      <div className="relative h-screen bg-black" onClick={handlePlayPause}>
        <div className="absolute inset-0 flex items-center justify-center">
          {movie.videoUrl ? (
            <ReactPlayer
              ref={playerRef}
              url={movie.videoUrl}
              playing={playing}
              muted={muted}
              volume={volume}
              width="100%"
              height="100%"
              style={{ objectFit: 'contain' }}
              onReady={() => setLoading(false)}
              onPlay={() => setPlaying(true)}
              onPause={() => setPlaying(false)}
              config={{
                file: {
                  forceshader: true
                }
              }}
            />
          ) : (
            <div className="flex flex-col items-center justify-center">
              <Play size={64} className="text-netflix-text-secondary mb-4" />
              <p className="text-netflix-text-secondary text-lg">Video not available</p>
              <Link to={`/movie/${id}`} className="btn-primary mt-4">
                View Details
              </Link>
            </div>
          )}
        </div>

        {!playing && (
          <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
            <Play size={64} className="text-white/80" />
          </div>
        )}

        <div className="absolute bottom-0 left-0 right-0 bg-gradient-to-t from-black to-transparent p-8">
          <h1 className="text-2xl md:text-3xl font-bold text-white mb-2">{movie.title}</h1>

          <div className="flex items-center gap-4">
            <button 
              onClick={handlePlayPause}
              className="w-14 h-14 rounded-full bg-white flex items-center justify-center hover:scale-110 transition-transform"
            >
              {playing ? <Pause size={24} className="text-black" /> : <Play size={24} className="text-black ml-1" />}
            </button>

            <button 
              onClick={() => setMuted(!muted)} 
              className="text-white hover:text-netflix-text-secondary transition-colors"
            >
              {muted ? <VolumeX size={24} /> : <Volume2 size={24} />}
            </button>

            <button 
              onClick={toggleFullscreen} 
              className="text-white hover:text-netflix-text-secondary transition-colors"
            >
              {fullscreen ? <Minimize size={24} /> : <Maximize size={24} />}
            </button>
          </div>
        </div>

        <div className="absolute top-20 right-8">
          <button className="text-white hover:text-netflix-text-secondary transition-colors">
            <Settings size={24} />
          </button>
        </div>
      </div>
    </div>
  );
};

export default WatchPage;
